import{_ as s,o as e,c as n,aQ as i}from"./chunks/framework.cDvftfeu.js";const k=JSON.parse('{"title":"Ham Web","description":"Ham Web前端架构和功能。","frontmatter":{"description":"Ham Web前端架构和功能。","prev":{"text":"品牌资源","link":"/developers/open-platform/brand-assets"},"next":{"text":"SSO OAuth2 授权","link":"/developers/ham-web/sso-authorize"}},"headers":[],"relativePath":"developers/ham-web/index.md","filePath":"developers/ham-web/index.md","lastUpdated":1777525243000}'),l={name:"developers/ham-web/index.md"};function t(p,a,r,o,h,d){return e(),n("div",null,[...a[0]||(a[0]=[i(`<h1 id="ham-web" tabindex="-1">Ham Web <a class="header-anchor" href="#ham-web" aria-label="Permalink to &quot;Ham Web&quot;">​</a></h1><p><a href="https://github.com/whu-ham/ham-web" target="_blank" rel="noreferrer">Ham Web</a> 是 Ham 的 Web 前端项目，主要承载 SSO 单点登录授权流程，并作为 Ham 互联平台的 Web 端入口。</p><h2 id="在哪里被使用" tabindex="-1">在哪里被使用 <a class="header-anchor" href="#在哪里被使用" aria-label="Permalink to &quot;在哪里被使用&quot;">​</a></h2><p>Ham Web 部署后作为 Ham 互联平台的 Web 服务端点，主要在以下场景中被使用：</p><ul><li><strong>SSO 授权页面</strong> — 当第三方应用通过 Ham 互联平台发起 OAuth2 授权时，用户会被重定向到 Ham Web 的授权页面进行登录和授权确认</li><li><strong>二维码登录</strong> — 用户可以在 Web 端通过扫描二维码完成登录</li><li><strong>Passkey 登录</strong> — 支持 WebAuthn / Passkey 无密码登录</li><li><strong>移动端 H5 回退</strong> — 当用户未安装 Ham 原生应用时，提供 Web 端的安装引导和 Passkey 登录选项</li></ul><h2 id="技术栈" tabindex="-1">技术栈 <a class="header-anchor" href="#技术栈" aria-label="Permalink to &quot;技术栈&quot;">​</a></h2><ul><li><strong>框架</strong>: Next.js 16（App Router）+ React 19 + TypeScript</li><li><strong>样式</strong>: Tailwind CSS v4 + HeroUI v3</li><li><strong>状态管理</strong>: Jotai + React Redux</li><li><strong>国际化</strong>: next-intl（支持中文 / 英文 / 日文）</li><li><strong>部署</strong>: Cloudflare Pages（通过 OpenNext）</li><li><strong>工具链</strong>: ESLint v9 + Prettier + pnpm</li></ul><h2 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to &quot;快速开始&quot;">​</a></h2><h3 id="前置要求" tabindex="-1">前置要求 <a class="header-anchor" href="#前置要求" aria-label="Permalink to &quot;前置要求&quot;">​</a></h3><ul><li>Node.js &gt;= 20</li><li>pnpm</li></ul><h3 id="安装与运行" tabindex="-1">安装与运行 <a class="header-anchor" href="#安装与运行" aria-label="Permalink to &quot;安装与运行&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 安装依赖</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 启动开发服务器（Turbopack）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 生产构建</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Cloudflare Pages 构建</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build:cf</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 代码检查</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lint</span></span></code></pre></div><p>开发服务器运行在 <code>http://localhost:3000</code>。</p><h2 id="项目结构" tabindex="-1">项目结构 <a class="header-anchor" href="#项目结构" aria-label="Permalink to &quot;项目结构&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>app/                # Next.js App Router 入口</span></span>
<span class="line"><span>  api/              # API 路由</span></span>
<span class="line"><span>    auth/           # 认证相关 API（登录、登出、刷新、Passkey、二维码）</span></span>
<span class="line"><span>    sso/            # SSO 相关 API（授权确认、授权信息）</span></span>
<span class="line"><span>  sso-authorize/    # SSO 授权页面（登录视图、二维码登录、Passkey 登录）</span></span>
<span class="line"><span>components/         # 共享 UI 组件</span></span>
<span class="line"><span>  LanguageSwitcher  # 语言切换器</span></span>
<span class="line"><span>  ThemeSwitcher     # 主题切换器</span></span>
<span class="line"><span>  SearchBar         # 搜索栏</span></span>
<span class="line"><span>i18n/               # next-intl 运行时配置</span></span>
<span class="line"><span>messages/           # 多语言翻译文件（en.json / zh.json / ja.json）</span></span>
<span class="line"><span>services/           # API / 服务层</span></span>
<span class="line"><span>store/              # 状态管理（locale、theme）</span></span>
<span class="line"><span>public/             # 静态资源</span></span></code></pre></div><h2 id="开发指南" tabindex="-1">开发指南 <a class="header-anchor" href="#开发指南" aria-label="Permalink to &quot;开发指南&quot;">​</a></h2><h3 id="添加新的-ui-文案" tabindex="-1">添加新的 UI 文案 <a class="header-anchor" href="#添加新的-ui-文案" aria-label="Permalink to &quot;添加新的 UI 文案&quot;">​</a></h3><p>使用 <code>next-intl</code> 进行国际化。添加新文案时，需要同时更新三个翻译文件：</p><ul><li><code>messages/zh.json</code></li><li><code>messages/en.json</code></li><li><code>messages/ja.json</code></li></ul><h3 id="api-路由" tabindex="-1">API 路由 <a class="header-anchor" href="#api-路由" aria-label="Permalink to &quot;API 路由&quot;">​</a></h3><p>Ham Web 的 API 路由作为后端代理，将请求转发到 Ham 后端服务：</p><ul><li><code>/api/auth/*</code> — 认证相关（登录、登出、Token 刷新、Passkey、二维码）</li><li><code>/api/sso/*</code> — SSO 授权相关（授权信息查询、授权确认）</li></ul><h3 id="主题与语言" tabindex="-1">主题与语言 <a class="header-anchor" href="#主题与语言" aria-label="Permalink to &quot;主题与语言&quot;">​</a></h3><ul><li>支持亮色 / 暗色 / 跟随系统三种主题模式</li><li>支持中文 / 英文 / 日文三种语言，通过 Cookie 持久化用户偏好</li></ul><h2 id="ci-cd" tabindex="-1">CI/CD <a class="header-anchor" href="#ci-cd" aria-label="Permalink to &quot;CI/CD&quot;">​</a></h2><p>项目通过 GitHub Actions 进行持续集成，并部署到 Cloudflare Pages。</p><h2 id="贡献指南" tabindex="-1">贡献指南 <a class="header-anchor" href="#贡献指南" aria-label="Permalink to &quot;贡献指南&quot;">​</a></h2><p>所有贡献者需遵循以下规则：</p><ol><li>提交前必须通过 <code>pnpm lint</code> 和 <code>pnpm build</code></li><li>提交信息遵循 <a href="https://www.conventionalcommits.org/" target="_blank" rel="noreferrer">Conventional Commits</a> 规范</li><li>提交信息和代码注释使用英文</li></ol><h2 id="许可证" tabindex="-1">许可证 <a class="header-anchor" href="#许可证" aria-label="Permalink to &quot;许可证&quot;">​</a></h2><p>Ham Web 采用 <a href="https://opensource.org/licenses/MIT" target="_blank" rel="noreferrer">MIT 许可证</a>。</p>`,31)])])}const u=s(l,[["render",t]]);export{k as __pageData,u as default};
